pragma solidity ^0.8.7;

contract NFTMintingContract {
    string public baseURI;
    uint public maxSupply;
    enum SaleState { NotActive, PresaleActive, PublicSaleActive }
    SaleState public saleState;
    uint public mintPrice;
    uint public preSaleLimit;

    mapping(address => bool) public whiteList;
    mapping(address => bool) public redeemed;

    event RedeemEvent(address indexed user);

    modifier onlyOwner() {
        // Placeholder for owner check
        require(msg.sender == address(0), "Not the contract owner");
        _;
    }

    modifier onlyWhitelisted() {
        require(whiteList[msg.sender], "Not whitelisted");
        _;
    }

    constructor(string memory _baseURI, uint _maxSupply, uint _mintPrice, uint _preSaleLimit) {
        baseURI = _baseURI;
        maxSupply = _maxSupply;
        mintPrice = _mintPrice;
        preSaleLimit = _preSaleLimit;
        saleState = SaleState.NotActive;
    }

    function setSaleState(SaleState _saleState) external onlyOwner {
        saleState = _saleState;
    }

    function whitelist(address user) external onlyOwner {
        whiteList[user] = true;
    }

    function preSaleMint() external payable onlyWhitelisted {
        require(saleState == SaleState.PresaleActive, "Presale is not active");
        require(msg.value >= mintPrice, "Insufficient Ether");
        // Add minting logic here
    }

    function mint() external payable {
        require(saleState == SaleState.PublicSaleActive, "Public sale is not active");
        require(msg.value >= mintPrice, "Insufficient Ether");
        // Add minting logic here
    }

    function redeemBook() external {
        require(redeemed[msg.sender] == false, "Already redeemed");
        redeemed[msg.sender] = true;
        emit RedeemEvent(msg.sender);
        // Add redeeming logic here
    }
}

