    modifier inState(State state) {
        require(currentState == state, "Invalid state for this action");
        _;
    }

    function actionOpenTrading() external onlyOwner inState(State.TradingClosed) {
        currentState = State.TradingOpened;
    }

    function actionEnableSwapping() external onlyOwner inState(State.TradingOpened) {
        currentState = State.SwappingEnabled;
    }

    function actionTransferTokens(address to, uint256 value) external inState(State.TradingOpened) {
        require(balances[msg.sender] >= value, "Insufficient balance");
        // Implement transaction limits and fee deducting logic
        balances[msg.sender] -= value;
        balances[to] += value;
        emit TransferEvent(msg.sender, to, value);
