pragma solidity ^0.8.7;

contract NFTMintingContract {
    string public baseURI;
    uint256 public cost;
    uint256 public maxSupply;
    mapping(address => bool) public whitelistedAddresses;

    enum State { Paused, MintingOpen, Revealed }
    State public currentState;
    address public owner;

    event NFTMinted(address indexed to);
    event NFTRevealed(string baseURI);

    modifier onlyOwner() {
        require(msg.sender == owner, "Caller is not the owner");
        _;
    }

    modifier isWhitelisted() {
        require(whitelistedAddresses[msg.sender], "Address not whitelisted");
        _;
    }

    modifier hasPaid() {
        require(msg.value >= cost, "Insufficient payment");
        _;
    }

    constructor(string memory _baseURI, uint256 _cost, uint256 _maxSupply) {
        baseURI = _baseURI;
        cost = _cost;
        maxSupply = _maxSupply;
        currentState = State.Paused;
        owner = msg.sender;
    }

    function resumeMinting() external onlyOwner {
        currentState = State.MintingOpen;
    }

    function pauseMinting() external onlyOwner {
        currentState = State.Paused;
    }

    function mintNFT() external payable isWhitelisted hasPaid {
        require(currentState == State.MintingOpen, "Minting is not open");
        // Minting logic here
        emit NFTMinted(msg.sender);
    }

    function revealNFT() external onlyOwner {
        currentState = State.Revealed;
        emit NFTRevealed(baseURI);
    }

    function whitelistUser(address _user) external onlyOwner {
        whitelistedAddresses[_user] = true;
    }

    function setBaseURI(string memory _baseURI) external onlyOwner {
        baseURI = _baseURI;
    }

    function setCost(uint256 _cost) external onlyOwner {
        cost = _cost;
    }

    function setMaxSupply(uint256 _maxSupply) external onlyOwner {
        maxSupply = _maxSupply;
    }
}

