pragma solidity ^0.8.4;

contract TokenContract {
    mapping(address => uint) public balances;
    uint public maxTxAmount = 1000;
    uint public devFee = 5;
    uint public rewardsFee = 2;

    enum State { Initialized, Transferring, Swapping }
    State public currentState;

    event Transfer(address indexed from, address indexed to, uint value);
    event FeesChanged(uint devFee, uint rewardsFee);
    event OnSwapAndRedirectEthFees(uint amount);

    constructor() {
        currentState = State.Initialized;
        mintTokens();
    }

    function mintTokens() internal {
        // Logic to mint tokens at initialization.
        currentState = State.Transferring;
    }

    function transfer(address to, uint amount) public {
        require(currentState == State.Transferring, "Not in transferring state");
        require(amount <= maxTxAmount, "Transfer exceeds max transaction amount");

        balances[msg.sender] -= amount;
        balances[to] += amount;

        emit Transfer(msg.sender, to, amount);

        // Trigger fee calculation
        calculateFees(amount);
    }

    function calculateFees(uint amount) internal {
        uint fees = (amount * (devFee + rewardsFee)) / 100;

        // Condition to check if fees are applicable before moving to Swapping state
        if (fees > 0) {
            currentState = State.Swapping;
            swapAndRedirectEthFees(fees);
        }
    }

    function swapAndRedirectEthFees(uint fees) internal {
        // Logic to swap tokens for ETH and redirect fees
        currentState = State.Transferring;

        emit OnSwapAndRedirectEthFees(fees);
    }

    function setMaxTxPercent(uint _maxTxPercent) external {
        maxTxAmount = _maxTxPercent;
        emit FeesChanged(devFee, rewardsFee);
    }

    function excludeFromFee(address account) external {
        // Logic to exclude an address from fee calculations
    }
}

