    modifier inState(State expectedState) {
        require(currentState == expectedState, "Invalid state for this operation");
        _;
    }

    constructor() {
        owner = msg.sender;
        currentState = State.MintDisabled;
    }

    function allowPublicMinting() external onlyOwner inState(State.MintDisabled) {
        currentState = State.MintEnabled;
    }

    function mintTokens() external payable inState(State.MintEnabled) {
        require(msg.value >= mintCost, "Insufficient payment");
        require(currentSupply < maxSupply, "Max supply reached");

        uint tokenId = currentSupply;
        currentSupply++;

        emit NFTMinted(msg.sender, tokenId);
    }

    function startGame() external onlyOwner inState(State.MintEnabled) {
        currentState = State.GameSetup;
        emit GameStarted();
    }

    function setupGame() external onlyOwner inState(State.GameSetup) {
        currentState = State.GameParticipation;
    }

    function participateGame() external inState(State.GameParticipation) {
        // Participation logic here
    }

    function claimRewards() external inState(State.GameParticipation) {
        uint rewardAmount = reputation[msg.sender];
        reputation[msg.sender] = 0;

        emit TokensClaimed(msg.sender, rewardAmount);
        // Logic to transfer tokens to claimant
    }
}

