pragma solidity ^0.8.0;

contract TokenContract {
    string public baseTokenURI;
    uint public price;
    bool public paused;
    address public vaultAddress;

    enum State { Paused, ActiveForMinting }
    State public currentState;

    event TokenMinted(address indexed to, uint tokenId);
    event PriceChanged(uint newPrice);
    event ContractStateChanged(State newState);

    modifier onlyOwner() {
        require(msg.sender == vaultAddress, "Not the contract owner");
        _;
    }

    constructor(string memory _baseTokenURI, uint _initialPrice, address _vaultAddress) {
        baseTokenURI = _baseTokenURI;
        price = _initialPrice;
        paused = true;
        vaultAddress = _vaultAddress;
        currentState = State.Paused;
    }

    function activateContract() external onlyOwner {
        require(currentState == State.Paused, "Contract is already active");
        currentState = State.ActiveForMinting;
        paused = false;
        emit ContractStateChanged(currentState);
    }

    function pauseContract() external onlyOwner {
        require(currentState == State.ActiveForMinting, "Contract is already paused");
        currentState = State.Paused;
        paused = true;
        emit ContractStateChanged(currentState);
    }

    function mintTokens(uint tokenId) external payable {
        require(currentState == State.ActiveForMinting, "Minting is paused");
        require(msg.value >= price, "Insufficient payment");

        // Implement token minting logic (omitted for brevity)
        emit TokenMinted(msg.sender, tokenId);
    }

    function setPrice(uint newPrice) external onlyOwner {
        price = newPrice;
        emit PriceChanged(newPrice);
    }

    function reserveTokens(address to, uint tokenId) external onlyOwner {
        // Implement token reservation logic (omitted for brevity)
        emit TokenMinted(to, tokenId);
    }

    function withdraw() external onlyOwner {
        payable(vaultAddress).transfer(address(this).balance);
    }
}

