    function depositVirtualAwoo(uint amount) external onlyActive {
        _virtualBalance[msg.sender] += amount;
        // Logic for depositing
    }

    function withdrawVirtualAwoo(uint amount) external onlyActive {
        require(_virtualBalance[msg.sender] >= amount, "Insufficient balance.");
        _virtualBalance[msg.sender] -= amount;
