    }

    function spendVirtualAwoo(uint amount) external onlyActive {
        require(_virtualBalance[msg.sender] >= amount, "Insufficient balance.");
        _virtualBalance[msg.sender] -= amount;
        emit VirtualAwooSpent(msg.sender, amount);
        // Logic for spending
