pragma solidity ^0.8.4;

contract FundManagementContract {
    // State variables
    mapping(address => address) public pools;
    address public owner;

    // Events
    event PoolAdded(address indexed pool, address rewardToken);
    event PoolRemoved(address indexed pool);
    event RequestTransfer(address indexed pool, address to, uint amount);
    event RescueFunds(address indexed to, uint amount);

    // Modifiers
    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    // Constructor
    constructor() {
        owner = msg.sender;
    }

    // Function to add a new pool
    function addPool(address pool, address rewardToken) external onlyOwner {
        pools[pool] = rewardToken;
        emit PoolAdded(pool, rewardToken);
    }

    // Function to remove an existing pool
    function removePool(address pool) external onlyOwner {
        delete pools[pool];
        emit PoolRemoved(pool);
    }

    // Function to transfer funds to a designated receiver
    function transferTo(address pool, address to, uint amount) external {
        require(pools[pool] != address(0), "Pool does not exist");
        // Logic to transfer funds...
        emit RequestTransfer(pool, to, amount);
    }

    // Function to rescue funds back to the owner's address
    function rescueFund(address to, uint amount) external onlyOwner {
        // Logic to rescue funds...
        emit RescueFunds(to, amount);
    }
}

